import{_ as a,o as s,c as t,a5 as r}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：UPS 参数保存与默认值恢复（parameter storage and default restore）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：UPS 参数保存与默认值恢复（parameter storage and default restore）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0035-ups-parameter-storage.html` 的源稿和补充资料。它只使用教学非易失存储记录，不包含公司内部NVM格式、Flash 地址、客户项目参数、未公开产品阈值或内部校验算法。"},"headers":[],"relativePath":"content/power/concepts/embedded/ups-parameter-storage.md","filePath":"content/power/concepts/embedded/ups-parameter-storage.md","lastUpdated":null}'),o={name:"content/power/concepts/embedded/ups-parameter-storage.md"};function l(n,e,p,i,d,c){return s(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="概念-ups-参数保存与默认值恢复-parameter-storage-and-default-restore" tabindex="-1">概念：UPS 参数保存与默认值恢复（parameter storage and default restore） <a class="header-anchor" href="#概念-ups-参数保存与默认值恢复-parameter-storage-and-default-restore" aria-label="Permalink to &quot;概念：UPS 参数保存与默认值恢复（parameter storage and default restore）&quot;">​</a></h1><p>本页是 <code>lessons/0035-ups-parameter-storage.html</code> 的源稿和补充资料。它只使用教学非易失存储记录，不包含公司内部NVM格式、Flash 地址、客户项目参数、未公开产品阈值或内部校验算法。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>非易失存储（non-volatile memory / NVM）是在断电后仍能保留数据的存储区域。参数保存是把参数表（parameter table）的当前值写入 NVM；默认值恢复（default restore）是在存储记录无效、版本不匹配或校验失败时回到安全的默认参数。</p><p>校验和（checksum）是用一组数据计算出的简短校验值，用来判断存储内容是否被破坏。本课只讲一个概念：保存参数时要同时保存版本、有效标志和校验和，加载失败时必须回默认值。</p><h2 id="为什么-ups-需要它" tabindex="-1">为什么 UPS 需要它 <a class="header-anchor" href="#为什么-ups-需要它" aria-label="Permalink to &quot;为什么 UPS 需要它&quot;">​</a></h2><p>上一节讲参数访问（parameter access）：通信可以改某些可写参数。但写入 RAM 后，如果掉电不保存，下次上电就丢失；如果保存内容损坏还盲目使用，保护阈值或控制参数可能变得不可预期。</p><p>UPS 上电时必须知道当前使用的参数来自哪里：是默认值，还是通过校验的已保存参数。这个来源本身就是调试和导师复盘的重要证据。</p><h2 id="物理直觉" tabindex="-1">物理直觉 <a class="header-anchor" href="#物理直觉" aria-label="Permalink to &quot;物理直觉&quot;">​</a></h2><p>参数保存像把调好的旋钮位置写进笔记本；校验和像笔记本最后的核对签名。下次开机先检查签名，如果签名对，就按笔记本恢复；如果签名不对，就不要相信这页纸，回到出厂默认值。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>save(parameters):</span></span>
<span class="line"><span>    record.version = 1</span></span>
<span class="line"><span>    record.valid = 1</span></span>
<span class="line"><span>    record.parameters = parameters</span></span>
<span class="line"><span>    record.checksum = checksum(version, parameters)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>load(record):</span></span>
<span class="line"><span>    if record.valid and record.checksum == checksum(record.version, record.parameters):</span></span>
<span class="line"><span>        return record.parameters, loaded_default = 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    return default_parameters, loaded_default = 1</span></span></code></pre></div><p>本课的 checksum 是教学用简化计算，不代表真实产品算法。</p><h2 id="仿真观察" tabindex="-1">仿真观察 <a class="header-anchor" href="#仿真观察" aria-label="Permalink to &quot;仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_parameter_storage.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>默认生成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/results/ups_parameter_storage.png</span></span></code></pre></div><p>图中包含保存/加载后的 <code>mains_uv_threshold_v</code>、校验是否通过、记录是否损坏、是否加载默认值。默认不加 <code>--no-open</code> 时脚本会尝试自动打开图片；打不开时会打印完整路径。</p><h2 id="固件落地" tabindex="-1">固件落地 <a class="header-anchor" href="#固件落地" aria-label="Permalink to &quot;固件落地&quot;">​</a></h2><ul><li><code>UpsParameterStorageRecord</code>：教学 NVM 记录，包含版本号、有效标志、校验和和参数快照。</li><li><code>version</code>：参数格式版本。</li><li><code>valid</code>：记录是否被认为有效。</li><li><code>checksum</code>：参数记录校验值。</li><li><code>UpsParameterStorage_Save()</code>：把当前参数打包成存储记录。</li><li><code>UpsParameterStorage_LoadOrDefault()</code>：校验记录，成功则加载保存值，失败则加载默认值。</li><li><code>loaded_default</code>：说明本次加载是否回到默认值。</li><li><code>checksum_ok</code>：说明本次校验是否通过。</li></ul><p>真实工程还会涉及 Flash 扇区擦写、磨损均衡、双备份、掉电中断保护、参数版本迁移和恢复默认值命令。本课只训练阅读主线。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>错误理解：参数写成功就等于永久保存。<br> 正确理解：RAM 写成功和 NVM 保存成功是两件事。</li><li>错误理解：NVM 里有数据就可以直接用。<br> 正确理解：必须检查有效标志、版本和校验和。</li><li>错误理解：可以把导师给的真实 NVM 记录格式写进学习仓库。<br> 正确理解：不能记录公司内部NVM格式，只能记录通用字段和阅读问题。</li></ul><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能运行 <code>python simulations\\python\\ups_parameter_storage.py --no-open</code> 并打开 <code>simulations/results/ups_parameter_storage.png</code>。</li><li>能解释 NVM、校验和、版本号、有效标志和默认值恢复分别解决什么问题。</li><li>能解释为什么校验失败时不能继续使用保存值。</li><li>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>parameter_storage</code> 输出。</li><li>能基于 <code>parameter_storage.c -&gt; UpsParameterStorage_LoadOrDefault()</code> 准备导师问题。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><ul><li>我用 <code>parameter_storage.c -&gt; UpsParameterStorage_LoadOrDefault()</code> 在校验失败时回默认值。真实工程里通常还会检查哪些通用字段？</li><li>我用 <code>simulations/results/ups_parameter_storage.png</code> 看到损坏记录会恢复 180 V 默认值。真实工程中恢复默认值后会不会记录日志或上报告警？</li><li>我不会记录公司内部NVM格式，只想确认阅读方式：看真实工程时，应先看参数版本、校验算法、双备份策略，还是恢复默认值入口？</li></ul>`,28)])])}const m=a(o,[["render",l]]);export{u as __pageData,m as default};
